impl Solution { pub fn insert_greatest_common_divisors(mut head: Option<Box<ListNode>>) -> Option<Box<ListNode>> { let mut black_curr = head.as_mut(); while let Some(node) = black_curr { if let Some(mut next_node) = node.next.take() { fn gcd(a: i32, b: i32) -> i32 { if b == 0 { a } else { gcd(b, a % b) } } node.next = Some(Box::new(ListNode { val: gcd(node.val, next_node.val), next: Some(next_node) })); black_curr = node.next.as_mut().unwrap().next.as_mut(); } else { break; } } head } }